int a = 5;
int b = 2;
System.out.println(a / b);        // 2 (int / int = int)
System.out.println((double) a / b); // 2.5 (one side is now double)

int x = 10;
x += 5; // x is now 15
x -= 3; // x is now 12

int count = 5;
count++; // count is now 6
count--; // count is now 5 again

int a = 5;
int b = a++; // b = 5, then a becomes 6  (post: use old value, then increment)

int c = 5;
int d = ++c; // c becomes 6, then d = 6  (pre: increment first, then use new value)

boolean age18Plus = true;
boolean hasId = false;

boolean canEnter = age18Plus && hasId;
System.out.println(canEnter); // false, because hasId is false

public class Main {
    public static void main(String[] args) {
        int a = 7;
        int b = 2;

        System.out.println("a / b = " + (a / b));
        System.out.println("a % b = " + (a % b));

        boolean isEven = (a % 2 == 0);
        System.out.println("Is a even? " + isEven);

        int score = 10;
        score += 5;
        System.out.println("Score: " + score);
    }
}

